You are implementing Task 5: Audio Player and Voice Connection for a Discord music bot.

## Task Description

**Files:**
- Create: `player/player.js`

- [ ] **Step 1: Create player/player.js**

```javascript
const {
  joinVoiceChannel,
  createAudioPlayer,
  createAudioResource,
  AudioPlayerStatus,
  StreamType,
} = require('@discordjs/voice');
const { spawn } = require('child_process');

let connection = null;
let audioPlayer = null;
let idleTimer = null;
let currentTextChannel = null;

const IDLE_TIMEOUT = parseInt(process.env.IDLE_TIMEOUT_MS || '300000', 10);

function joinChannel(voiceChannel) {
  if (connection) connection.destroy();

  connection = joinVoiceChannel({
    channelId: voiceChannel.id,
    guildId: voiceChannel.guild.id,
    adapterCreator: voiceChannel.guild.voiceAdapterCreator,
  });

  audioPlayer = createAudioPlayer();
  audioPlayer.on(AudioPlayerStatus.Idle, _onIdle);
  audioPlayer.on('error', err => {
    console.error('Audio player error:', err.message);
    _onIdle();
  });
  connection.subscribe(audioPlayer);
}

function playTrack(url, textChannel) {
  currentTextChannel = textChannel;
  _clearIdleTimer();

  const ytdlp = spawn('yt-dlp', ['-f', 'bestaudio', '--no-playlist', '-o', '-', url], {
    stdio: ['ignore', 'pipe', 'ignore'],
  });

  ytdlp.on('error', err => {
    console.error('yt-dlp stream error:', err.message);
    _onIdle();
  });

  const resource = createAudioResource(ytdlp.stdout, { inputType: StreamType.Arbitrary });
  audioPlayer.play(resource);
}

function _onIdle() {
  const queue = require('./queue');
  if (!queue.isEmpty()) {
    const next = queue.dequeue();
    currentTextChannel?.send(`▶️ Now playing: **${next.title}**`);
    playTrack(next.url, currentTextChannel);
  } else {
    _startIdleTimer();
  }
}

function _startIdleTimer() {
  idleTimer = setTimeout(() => {
    currentTextChannel?.send('👋 Left voice channel due to inactivity.');
    disconnect();
  }, IDLE_TIMEOUT);
}

function _clearIdleTimer() {
  if (idleTimer) {
    clearTimeout(idleTimer);
    idleTimer = null;
  }
}

function stopCurrent() {
  if (audioPlayer) audioPlayer.stop();
}

function disconnect() {
  _clearIdleTimer();
  require('./queue').clear();
  currentTextChannel = null;
  if (connection) {
    connection.destroy();
    connection = null;
  }
  audioPlayer = null;
}

function isConnected() {
  return connection !== null && audioPlayer !== null;
}

module.exports = { joinChannel, playTrack, stopCurrent, disconnect, isConnected };
```

- [ ] **Step 2: Commit**

```bash
git add player/player.js
git commit -m "feat: add voice connection and audio streaming"
```

## Context

Working directory: `/Users/rohanpuri/Desktop/Projects/Discord-Bot`. Tasks 1-4 complete.

Key architectural details:
- Module-level state (connection, audioPlayer, idleTimer, currentTextChannel) — fine for single server bot
- `joinChannel(voiceChannel)` — takes a Discord.js VoiceChannel object, creates the voice connection, sets up audioPlayer and subscribes it
- `playTrack(url, textChannel)` — spawns yt-dlp as child process piping audio to @discordjs/voice. Uses `StreamType.Arbitrary` which tells @discordjs/voice to run ffmpeg for transcoding (ffmpeg IS installed)
- `_onIdle()` — called when track ends OR on error. Checks queue for next track. If empty, starts idle timer.
- `_startIdleTimer()` — after IDLE_TIMEOUT_MS (default 5 min), sends inactivity message and disconnects
- `stopCurrent()` — calls audioPlayer.stop() which triggers the Idle event → _onIdle → plays next or starts timer
- `disconnect()` — clears timer, clears queue, destroys connection, nulls everything
- `isConnected()` — used by command handlers to check state before acting
- Lazy require of './queue' inside _onIdle and disconnect to avoid circular dependency issues at module load time

The `_onIdle` lazy require pattern is intentional — `player.js` and `queue.js` are siblings in the same folder and can be required lazily inside functions without issue in Node.js CommonJS.

